1	#!/usr/bin/env node
2	/**
3	 * Scenario runner TEMPLATE — copy this to `sdk/org/scenarios/<id>/run.mjs` and fill in the Acts.
4	 * It bakes in every hardening pattern the campaigns learned the hard way (see the harness API +
5	 * hardening patterns in automation/instances/scenario-campaign/prompt.common.md): per-Act
6	 * checkpointing + resume, a keepalive pinger, a resilient `send`
7	 * that survives a full pod restart, a scripted ask answerer, attachment + live-app + inbound helpers,
8	 * and trace-based assertions.
9	 *
10	 * NOTE: `ThingSession` now self-heals SESSION EVICTION natively (a long turn's sub-sessions can push
11	 * a small pod past MAX_SESSIONS): pullEvents treats a post-work 404 as turn-complete, and it
12	 * re-establishes an evicted session before the next send. The `thing.send` wrapper below is the extra
13	 * belt for a FULL pod roll/restart. For a session-heavy scenario, also raise the cap on the test pod:
14	 *   ssh … 'kubectl set env deployment/lmthing MAX_SESSIONS=25 -n user-<id>'
15	 *
16	 *   cd sdk/org/scenarios/harness && node ../<id>/run.mjs [--acts=1,2,3] [--fresh]
17	 *
18	 * Replace every `SCENARIO_*` below, then write your Acts where marked.
19	 */
20	import { existsSync, mkdirSync, readFileSync, writeFileSync } from 'node:fs';
21	import { createHmac } from 'node:crypto';
22	import { getUser } from '../harness/provision.mjs';
23	import { Pod } from '../harness/lib/pod.mjs';
24	import { ThingSession } from '../harness/lib/thing.mjs';
25	import { Report } from '../harness/lib/report.mjs';
26	import { mergePodEnv, waitPodReady, waitPodSettled } from '../harness/lib/gateway.mjs';
27	import { SDK_ORG } from '../harness/lib/paths.mjs';
28	
29	// ── config — EDIT THESE ─────────────────────────────────────────────────────────
30	const ID = 'SCENARIO_ID'; // e.g. '06-something'
31	const TITLE = 'SCENARIO_TITLE';
32	const LABEL = 'SCENARIO_LABEL'; // provision.mjs label (disposable user prefix)
33	const PROJECT = 'SCENARIO_PROJECT'; // the project id the scenario runs in ('user' = default)
34	/** Any integration/env secrets the scenario needs, loaded BEFORE the first session. */
35	const POD_ENV = {
36	  // INTEGRATION_DEMO_BASE_URL: 'https://httpbin.org/anything',
37	  // INTEGRATION_DEMO_API_TOKEN: 'demo-token',
38	  // INTEGRATION_DEMO_WEBHOOK_SECRET: 'demo-hmac-secret',
39	};
40	
41	const RESULTS = `${SDK_ORG}/scenarios/${ID}/results`;
42	const CHECKPOINT = `${RESULTS}/checkpoint.json`;
43	const argActs = (process.argv.find((a) => a.startsWith('--acts=')) ?? '').slice(7);
44	const ACTS = argActs ? argActs.split(',').map(Number) : [1, 2, 3, 4];
45	const FRESH = process.argv.includes('--fresh');
46	const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
47	const now = () => Date.now();
48	
49	// ── checkpoint (resume from the last good Act) ──────────────────────────────────
50	function loadCheckpoint() {
51	  if (FRESH || !existsSync(CHECKPOINT)) return { acts: {}, sessionId: null };
52	  try { return JSON.parse(readFileSync(CHECKPOINT, 'utf8')); } catch { return { acts: {}, sessionId: null }; }
53	}
54	function saveCheckpoint(cp) {
55	  mkdirSync(RESULTS, { recursive: true });
56	  writeFileSync(CHECKPOINT, JSON.stringify(cp, null, 2));
57	  console.log(`\n💾 checkpoint → ${CHECKPOINT}`);
58	}
59	
60	// ── scripted asks: approve/deny consent, settle any other ask so a run never hangs ──
61	const scriptedOnAsk = (consent) => (d) => {
62	  if (d?.type === 'ConsentCard') return consent;
63	  if (d?.type) return {}; // settle Forms/other asks with an empty submission
64	  return undefined;
65	};
66	
67	// ── signed inbound helper (a provider-shaped, HMAC-signed webhook to the pod) ────
68	function signedInbound(pod, path, body, secret, header = 'x-demo-signature') {
69	  const raw = typeof body === 'string' ? body : JSON.stringify(body);
70	  const sig = 'sha256=' + createHmac('sha256', secret).update(raw).digest('hex');
71	  return pod.inbound(path, raw, { [header]: sig });
72	}
73	
74	// ── project-app assertion helper (build + read real rows) ────────────────────────
75	// A real live-project app: compile it and confirm real assets came out, then read its DB rows.
76	// (`built` lives at manifest.build.built and only reflects the LAST compile — so build explicitly
77	//  and read the POST result, which carries assetManifest + routes — see the harness gotchas in the campaign prompt.)
78	async function assertLiveApp(report, pod, projectId, { minRowTables = {} } = {}) {
79	  const build = await pod.appBuild(projectId).catch((e) => ({ built: false, error: String(e) }));
80	  const assets = build?.assetManifest ?? [];
81	  report.check('app compiles (built:true) with real JS assets', build?.built === true && assets.some((a) => /\.js$/.test(a)), JSON.stringify({ built: build?.built, assets }).slice(0, 200));
82	  report.check('app serves ≥1 page route', (build?.routes?.length ?? 0) >= 1, (build?.routes ?? []).map((x) => x.routePath).join(', '));
83	  const page = await pod.appPage(projectId).catch((e) => ({ status: 0, body: String(e) }));
84	  report.check(`/app/${projectId}/ serves 200 HTML`, page.status === 200 && String(page.body).includes('<!doctype'), `status ${page.status}, ${String(page.body).length} bytes`);
85	  // minRowTables: { <table-regex>: <min rows> } — assert real data landed (moved into the db).
86	  const manifest = await pod.appManifest(projectId).catch(() => ({}));
87	  const names = (manifest?.tables ?? []).map((t) => (typeof t === 'string' ? t : t.name));
88	  for (const [rx, min] of Object.entries(minRowTables)) {
89	    const t = names.find((n) => new RegExp(rx, 'i').test(n));
90	    const rows = t ? (await pod.appData(projectId, t).catch(() => ({ rows: [] }))).rows ?? [] : [];
91	    report.check(`table /${rx}/ has ≥${min} rows`, rows.length >= min, `${t ?? '(none)'}: ${rows.length} rows`);
92	  }
93	  return build;
94	}
95	
96	// ── main ────────────────────────────────────────────────────────────────────────
97	const report = new Report(ID, TITLE);
98	const cp = loadCheckpoint();
99	const t0 = now();
100	
101	const user = await getUser(LABEL);
102	console.log(`user ${user.email} (${user.userId}) → ${user.pod}`);
103	
104	const { changed } = await mergePodEnv(user.token, POD_ENV);
105	if (changed) { await waitPodReady(user.token); await waitPodSettled(user.token); }
106	
107	const pod = new Pod({ base: user.pod, token: user.token });
108	const projects = await pod.listProjects();
109	if (PROJECT !== 'user' && !(projects.projects ?? []).some((p) => (p.id ?? p) === PROJECT)) {
110	  await pod.createProject(PROJECT);
111	}
112	cp.projectId = PROJECT;
113	cp.user = { label: LABEL, email: user.email, userId: user.userId };
114	
115	const thing = new ThingSession(pod, { projectId: PROJECT, onAsk: scriptedOnAsk(true), verbose: true });
116	if (cp.sessionId && !FRESH) {
117	  try { await thing.resume(cp.sessionId); } catch { cp.sessionId = await thing.start(); }
118	} else {
119	  cp.sessionId = await thing.start();
120	}
121	saveCheckpoint(cp);
122	
123	// keep the pod warm so an idle scale-to-zero never kills the session mid-run
124	const keepalive = setInterval(() => {
125	  pod.req('POST', '/api/keepalive', {}).catch(() => pod.req('POST', '/api/compute/wake', {}).catch(() => {}));
126	}, 30_000);
127	keepalive.unref?.();
128	
129	// resilient send: survive a pod roll/restart (also exercises the auto-resume edge)
130	const _send = thing.send.bind(thing);
131	thing.send = async (content, opts = {}) => {
132	  for (let attempt = 0; ; attempt++) {
133	    try { return await _send(content, opts); }
134	    catch (e) {
135	      const msg = String(e?.body?.error ?? e?.message ?? '');
136	      const lost = e?.status === 404 || /unknown session|404/.test(msg);
137	      const errored = /entered error state/.test(msg);
138	      if ((!lost && !errored) || attempt >= 3) throw e;
139	      await waitPodReady(user.token).catch(() => {});
140	      for (let i = 0; i < 40; i++) { if (await pod.listProjects().then(() => true).catch(() => false)) break; await sleep(4_000); }
141	      if (lost && !errored) { try { await thing.resume(cp.sessionId); continue; } catch { /* fresh */ } }
142	      cp.sessionId = await thing.start(); saveCheckpoint(cp);
143	    }
144	  }
145	};
146	
147	const metrics = { tokens: { in: 0, out: 0 } };
148	const acc = (turn) => { metrics.tokens.in += turn.tokens.in; metrics.tokens.out += turn.tokens.out; return turn; };
149	
150	// ═══ ACT I ════════════════════════════════════════════════════════════════════
151	if (ACTS.includes(1)) {
152	  report.step('Act I — <name>', '<the contract this Act asserts>');
153	  const t = acc(await thing.send('<the user message>', { timeoutMs: 900_000 }));
154	  report.check('no eval/typecheck errors', t.errors.length === 0, JSON.stringify(t.errors).slice(0, 200));
155	  // report.check('delegated to <space>', thing.didDelegate('<space>'), t.delegates.join(', '));
156	  // ...assert on the trace + real side effects (files/rows/spaces), not the prose...
157	  cp.acts.I = { passed: report.passed };
158	  saveCheckpoint(cp);
159	}
160	
161	// ═══ ACT II / III / IV — same shape; gate each on ACTS.includes(n) + checkpoint ═══
162	// (Toggle scripted consent for a deny branch: thing.onAsk = scriptedOnAsk(false); ... reset to true.)
163	//
164	// ── Example: a file attachment → a live app with the data seeded in (the S06 pattern) ──
165	// const attachment = await pod.upload(`${SDK_ORG}/scenarios/${ID}/fixtures/notes.md`);
166	// report.check('file uploaded (kind=file)', attachment.kind === 'file', attachment.mediaType);
167	// // Attachments ride the WS path (HTTP /message drops them). THING hands the file to a specialist
168	// // via attachmentIds; the automator readDocument()s it and seeds rows via writeProjectTable(...,rows).
169	// const t = acc(await thing.sendWithAttachments('<the user message>', [attachment], { timeoutMs: 1_500_000 }));
170	// report.check('read the file (system-files)', thing.didDelegate('system-files'), t.delegates.join(', '));
171	// await assertLiveApp(report, pod, PROJECT, { minRowTables: { 'flight|itinerary': 5, 'accommodation|hotel': 6 } });
172	//
173	// ── Example: a LATER update changes the db (use a NEW fact NOT already in any seed) ──
174	// const before = JSON.stringify(await pod.appData(PROJECT, '<table>').catch(() => ({})));
175	// acc(await thing.send('Mark X as done and record confirmation "NEW-TOKEN-123".', { timeoutMs: 900_000 }));
176	// await sleep(4_000);
177	// const after = JSON.stringify(await pod.appData(PROJECT, '<table>').catch(() => ({})));
178	// report.check('the NEW fact landed in the db', !before.includes('new-token-123') && after.toLowerCase().includes('new-token-123'), 'before/after diff');
179	//
180	// ── Example: a signed inbound webhook fires a code-handler hook (0 LLM) ──
181	// const res = await signedInbound(pod, 'demo', { message: { message_id: 1, text: 'TIP: hello', chat: { id: 'c1' }, from: { id: 'u1' } } }, POD_ENV.INTEGRATION_DEMO_WEBHOOK_SECRET);
182	// report.check('inbound accepted (verify→emit)', res.status === 200 && res.body?.events >= 1, JSON.stringify(res.body));
183	
184	// ═══ verdict ══════════════════════════════════════════════════════════════════
185	const stats = thing.stats();
186	report.step('Whole-session invariants', 'no eval/typecheck errors; routing not degraded over the run');
187	report.check('zero eval/typecheck errors across the session', stats.errors === 0, `${stats.errors} errors`);
188	report.metric('wall clock', ((now() - t0) / 60_000).toFixed(1), ' min');
189	report.metric('total tokens (in/out)', `${metrics.tokens.in} / ${metrics.tokens.out}`);
190	
191	report.save(`${RESULTS}/report.md`);
192	report.saveTrace(`${RESULTS}/trace.json`, thing);
193	cp.done = true; cp.summary = report.summary(); saveCheckpoint(cp);
194	console.log(JSON.stringify(report.summary(), null, 2));
195	process.exit(report.passed ? 0 : 1);
