1	/**
2	 * THING session driver — talks to a real agent session over the pod's HTTP API and gives a
3	 * scenario everything it needs to ASSERT on behaviour, not just on final text.
4	 *
5	 * Why HTTP and not the WebSocket the /chat SPA uses: the WS needs a dep and buys us nothing here.
6	 * The pod exposes the same surface over HTTP (sdk/org/libs/cli/src/server/web/agent-api.ts):
7	 *
8	 *   POST /api/sessions                      {projectId, agentSlug?, resumeSessionId?, budget?}
9	 *   POST /api/sessions/:id/message          {content}                         → 202
10	 *   GET  /api/sessions/:id/events?since=N&format=json                          → {events,lastSeq}
11	 *   GET  /api/sessions/:id/asks?format=json                                    → {asks}
12	 *   POST /api/sessions/:id/ask/:askId       {value}                            → answer a prompt
13	 *
14	 * The event stream is the full execution trace (sdk/org/libs/core/src/sandbox/trace.ts), so a
15	 * scenario can assert on the things that actually matter — which agents THING delegated to, which
16	 * consent-marked globals it called, which yields resolved, tokens burned, errors raised — instead
17	 * of grading a paragraph of prose.
18	 *
19	 * IMPORTANT (consent): the consent prompter is only wired for INTERACTIVE sessions
20	 * (session-manager.ts — `consentPrompter: args.interactive ? … : undefined`). A session created
21	 * through `POST /api/sessions` is interactive, so consent cards appear as asks here. Headless
22	 * paths (hooks, delegates, webhook dispatch) fail closed by design — that is a feature to assert,
23	 * not a bug to work around.
24	 */
25	
26	const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
27	
28	export class ThingSession {
29	  /**
30	   * @param {import('./pod.mjs').Pod} pod
31	   * @param {object} opts
32	   * @param {string} [opts.projectId='user']   project to run in ('user' = the default project)
33	   * @param {string} [opts.agentSlug='thing']  THING is the default agent
34	   * @param {(descriptor:object)=>unknown} [opts.onAsk]  answer asks (consent cards, forms).
35	   *        Return `undefined` to leave the ask open (the scenario answers it manually).
36	   * @param {boolean} [opts.verbose=false]     stream a live log to stdout
37	   */
38	  constructor(pod, opts = {}) {
39	    this.pod = pod;
40	    this.projectId = opts.projectId ?? 'user';
41	    this.agentSlug = opts.agentSlug ?? 'thing';
42	    this.onAsk = opts.onAsk;
43	    this.verbose = opts.verbose ?? false;
44	    this.sessionId = null;
45	    /** every trace event seen, in order — the scenario's source of truth */
46	    this.events = [];
47	    /** asks the driver saw, with what it answered */
48	    this.asks = [];
49	    this.lastSeq = 0;
50	  }
51	
52	  log(...a) {
53	    if (this.verbose) console.log('[thing]', ...a);
54	  }
55	
56	  /** Create the session. Init is async pod-side — `send()` waits it out. */
57	  async start({ resumeSessionId, budget } = {}) {
58	    const body = {
59	      projectId: this.projectId,
60	      agentSlug: this.agentSlug,
61	      ...(resumeSessionId ? { resumeSessionId } : {}),
62	      ...(budget ? { budget } : {}),
63	    };
64	    const { sessionId } = await this.pod.req('POST', '/api/sessions', body);
65	    this.sessionId = sessionId;
66	    this.log('session', sessionId);
67	    return sessionId;
68	  }
69	
70	  /** Resume an existing session id (post-restart auto-resume scenario). */
71	  async resume(sessionId) {
72	    return this.start({ resumeSessionId: sessionId });
73	  }
74	
75	  /**
76	   * Pull new trace events since `lastSeq`.
77	   *
78	   * A long turn can spawn many delegate/headless sub-sessions; on a small pod (`maxSessions`) the
79	   * session manager may EVICT this top-level session shortly after its turn completes, so a poll
80	   * then 404s ("unknown session"). That is not a turn failure — the work already landed (assert it
81	   * on real pod state). So a 404 is surfaced as a soft signal (`this.sessionGone = true`) rather
82	   * than thrown; the settle loop treats it as turn-end once work has been seen.
83	   */
84	  async pullEvents() {
85	    let res;
86	    try {
87	      res = await this.pod.req('GET', `/api/sessions/${this.sessionId}/events?since=${this.lastSeq}&format=json`);
88	    } catch (err) {
89	      if (err?.status === 404) {
90	        this.sessionGone = true;
91	        return [];
92	      }
93	      throw err;
94	    }
95	    const { events, lastSeq } = res;
96	    for (const e of events ?? []) {
97	      this.events.push(e.event);
98	      if (this.verbose) this.#logEvent(e.event);
99	    }
100	    if (typeof lastSeq === 'number') this.lastSeq = lastSeq;
101	    return events ?? [];
102	  }
103	
104	  #logEvent(ev) {
105	    switch (ev.type) {
106	      case 'yield':
107	        this.log(`  yield ${ev.kind}`, JSON.stringify(ev.args)?.slice(0, 140));
108	        break;
109	      case 'display':
110	        this.log('  display', JSON.stringify(ev.descriptor)?.slice(0, 200));
111	        break;
112	      case 'node_start':
113	        this.log(`  node_start ${ev.kind} ${ev.label}`);
114	        break;
115	      case 'node_end':
116	        this.log(`  node_end ${ev.nodeId} ${ev.status} ${ev.durationMs}ms`);
117	        break;
118	      case 'eval_error':
119	      case 'typecheck_error':
120	        this.log(`  !! ${ev.type}: ${ev.message?.slice(0, 200)}`);
121	        break;
122	      default:
123	        break;
124	    }
125	  }
126	
127	  /** Open asks, with the raw descriptor (a ConsentCard is `descriptor.type === 'ConsentCard'`). */
128	  async openAsks() {
129	    const { asks } = await this.pod.req('GET', `/api/sessions/${this.sessionId}/asks?format=json`);
130	    return asks ?? [];
131	  }
132	
133	  /**
134	   * Answer an ask. Consent approval is anything in {true, 'approve', {approved:true},
135	   * {approve:true}} (core/src/globals/consent.ts `isConsentApproval`); ANYTHING else — including
136	   * null — is a denial.
137	   */
138	  async answerAsk(askId, value) {
139	    await this.pod.req('POST', `/api/sessions/${this.sessionId}/ask/${askId}`, { value });
140	    this.log('answered ask', askId, JSON.stringify(value));
141	  }
142	
143	  /**
144	   * Send a user message and wait for the turn to settle.
145	   *
146	   * "Settled" = the session is idle AND the trace has stopped growing for `quietMs`. We can't
147	   * key on a single `turn_end` because delegates/forks emit their own in sub-contexts; the
148	   * idle+quiet pair is the only reliable edge over HTTP.
149	   *
150	   * While waiting we drain asks through `onAsk` — that is how consent cards get approved mid-turn.
151	   * A turn blocked on an unanswered ask never goes idle, so an un-handled consent card surfaces as
152	   * a timeout with the ask still open (which the scenario can assert on).
153	   */
154	  /**
155	   * Ensure `this.sessionId` still exists; if it was evicted (`maxSessions` on a small pod), start a
156	   * fresh session — resuming the old id when the pod still has its snapshot, else a clean new one.
157	   * The project (its spaces, app, db) persists on disk regardless, so a re-established session still
158	   * sees everything built so far; only in-VM conversation memory is lost (acceptable — the scenario
159	   * drives self-contained follow-ups).
160	   */
161	  async #ensureAlive() {
162	    if (!this.sessionId) return;
