240	
241	  async #dispatchAndWait(dispatch, logLine, { timeoutMs = 600_000, quietMs = 4_000, pollMs = 1_500 } = {}) {
242	    const startSeq = this.events.length;
243	    const t0 = Date.now();
244	    await dispatch();
245	    this.log('→', logLine.slice(0, 140));
246	
247	    let lastChange = Date.now();
248	    let sawWork = false;
249	    let quietSince = null;
250	    this.sessionGone = false;
251	
252	    while (Date.now() - t0 < timeoutMs) {
253	      const fresh = await this.pullEvents();
254	      if (fresh.length) {
255	        lastChange = Date.now();
256	        sawWork = true;
257	        quietSince = null;
258	      }
259	
260	      // If the session was evicted AFTER we saw the turn's work (a long turn's many sub-sessions
261	      // can push a small pod past `maxSessions`), the turn is effectively done — stop cleanly and
262	      // let the scenario assert on real pod state. If it vanished BEFORE any work, that's a real
263	      // failure (e.g. a mid-init pod restart), so surface it.
264	      if (this.sessionGone) {
265	        if (sawWork) return this.turn(startSeq, Date.now() - t0);
266	        throw new Error(`session ${this.sessionId} disappeared before doing any work (pod restart mid-init?)`);
267	      }
268	
269	      // Drain asks (consent cards, forms) — an unanswered ask stalls the turn forever.
270	      for (const ask of await this.openAsks().catch(() => [])) {
271	        if (this.asks.some((a) => a.id === ask.id)) continue;
272	        const answer = this.onAsk ? this.onAsk(ask.descriptor, ask) : undefined;
273	        this.asks.push({ id: ask.id, descriptor: ask.descriptor, answered: answer });
274	        if (answer !== undefined) {
275	          await this.answerAsk(ask.id, answer).catch(() => {});
276	          lastChange = Date.now();
277	        }
278	      }
279	
280	      const sessions = await this.pod.req('GET', '/api/sessions').catch(() => ({ sessions: [] }));
281	      const me = (sessions.sessions ?? []).find((s) => s.sessionId === this.sessionId);
282	      const idle = me?.status === 'idle';
283	      if (me?.status === 'error') {
284	        await this.pullEvents();
285	        throw new Error(`session entered error state: ${JSON.stringify(me)}`);
286	      }
287	      // Session no longer listed but we saw work → treat as completed (same eviction case).
288	      if (sawWork && !me && this.events.length > startSeq) {
289	        return this.turn(startSeq, Date.now() - t0);
290	      }
291	
292	      if (sawWork && idle && Date.now() - lastChange >= quietMs) {
293	        if (quietSince === null) quietSince = Date.now();
294	        await this.pullEvents(); // final drain
295	        return this.turn(startSeq, Date.now() - t0);
296	      }
297	      await sleep(pollMs);
298	    }
299	    await this.pullEvents();
300	    const open = await this.openAsks();
