302	      new Error(
303	        `turn timed out after ${timeoutMs}ms` +
304	          (open.length ? ` with ${open.length} unanswered ask(s): ${JSON.stringify(open)}` : ''),
305	      ),
306	      { turn: this.turn(startSeq, Date.now() - t0), openAsks: open },
307	    );
308	  }
309	
310	  /** A view over just the events of one turn, with the derived facts a scenario asserts on. */
311	  turn(startSeq = 0, durationMs = 0) {
312	    const evs = this.events.slice(startSeq);
313	    return {
314	      durationMs,
315	      events: evs,
316	      text: textOf(evs),
317	      yields: evs.filter((e) => e.type === 'yield').map((e) => ({ kind: e.kind, args: e.args })),
318	      delegates: evs
319	        .filter((e) => e.type === 'yield' && e.kind === 'delegate')
320	        .map((e) => delegateRef(e.args)),
321	      errors: evs
322	        .filter((e) => e.type === 'eval_error' || e.type === 'typecheck_error')
323	        .map((e) => ({ type: e.type, message: e.message, statement: e.statement })),
324	      tokens: evs.reduce(
325	        (acc, e) =>
326	          e.type === 'llm_response'
327	            ? { in: acc.in + (e.inputTokens ?? 0), out: acc.out + (e.outputTokens ?? 0) }
328	            : acc,
329	        { in: 0, out: 0 },
330	      ),
331	      llmCalls: evs.filter((e) => e.type === 'llm_response').length,
332	      nodes: evs
333	        .filter((e) => e.type === 'node_end')
334	        .map((e) => ({ id: e.nodeId, status: e.status, ms: e.durationMs, error: e.error })),
335	    };
336	  }
337	
338	  /** Did the agent call this yield kind anywhere in the session? (e.g. 'installSpace') */
339	  didYield = (kind) => this.events.some((e) => e.type === 'yield' && e.kind === kind);
340	  /** Did it delegate to this `space/agent` (or just this space)? */
341	  didDelegate = (ref) =>
342	    this.events.some(
343	      (e) => e.type === 'yield' && e.kind === 'delegate' && delegateRef(e.args).startsWith(ref),
