    broadcastUiControl: (action: UiControlAction) => void;
  },
): AgentApiContext {
  return {
    hub: entry.hub,
    spaceName: entry.spaceDir,
    agentSlug: entry.agentSlug,
    sendMessage: deps.sendMessage,
    submitForm: (id, value) => entry.renderHost.submitForm(id, value),
